import { DefaultSession } from "next-auth";

type UserRole = "OWNER" | "ADMIN" | "MODERATOR" | "VENDOR" | "CLIENT";

declare module "next-auth" {
  interface Session {
    user: {
      id: string;
      role: UserRole;
    } & DefaultSession["user"];
  }

  interface User {
    role: UserRole;
  }
}

declare module "next-auth/jwt" {
  interface JWT {
    id: string;
    role: UserRole;
  }
}
